const employees = $items("Find Employee Users").map(item => item.json);
if (!employees.length) throw new Error('No employee users found!');
const statuses = ['pending', 'in-progress', 'completed'];
const priorities = ['low', 'medium', 'high'];
const titles = [
  'Prepare monthly report',
  'Update client documentation',
  'Fix login bug',
  'Review pull request',
  'Organize team meeting',
  'Test new feature',
  'Refactor codebase',
  'Write unit tests',
  'Deploy to production',
  'Analyze user feedback',
  'Optimize database',
  'Design new UI',
  'Research competitors',
  'Update dependencies',
  'Document API changes',
  'Plan sprint tasks',
  'Clean up old files',
  'Prepare onboarding',
  'Sync with marketing',
  'Investigate error logs'
];
const descriptions = [
  'This task is important for the current sprint.',
  'Coordinate with the relevant team members.',
  'Ensure all changes are tested before deployment.',
  'Update the documentation as needed.',
  'Reach out to the client if clarification is needed.',
  'Double-check for edge cases and bugs.',
  'This is a high-priority item.',
  'Follow up after completion.',
  'Attach all relevant files.',
  'Provide a summary in the next meeting.'
];
const tasks = [];
for (let i = 0; i < 20; i++) {
  const emp = employees[Math.floor(Math.random() * employees.length)];
  const title = titles[Math.floor(Math.random() * titles.length)];
  const description = descriptions[Math.floor(Math.random() * descriptions.length)];
  tasks.push({
    title,
    description,
    status: statuses[Math.floor(Math.random() * statuses.length)],
    priority: priorities[Math.floor(Math.random() * priorities.length)],
    dueDate: new Date(Date.now() + Math.random() * 10 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    createdAt: new Date(Date.now() - Math.random() * 10 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
    assignedTo: emp._id,
    assignedEmail: emp.email,
    assignedName: emp.name
  });
}
return tasks.map(t => ({ json: t }));
